/d/project/pt-gitlab/survey-king/server/rdbms/build.gradle
plugins {
    id 'java'
}

version 'unspecified'

repositories {
    mavenCentral()
}

dependencies {
    implementation project(':shared')
    implementation 'com.baomidou:mybatis-plus-boot-starter:3.5.0'
    implementation 'org.springframework.boot:spring-boot-starter-security'
    implementation 'org.dhatim:fastexcel-reader:0.12.3'

//    implementation 'com.h2database:h2:2.1.214'
    implementation 'mysql:mysql-connector-java:8.0.26'
}

test {
    useJUnitPlatform()
}

plugins {
    id 'maven-publish'
}

project.archivesBaseName = 'surveyking'

ext {
    isProd = project.hasProperty("pro")
    isDev = project.hasProperty("dev")
    activeProfile = project.hasProperty("pro") ? "pro" : "dev"
}

configurations {
    compileOnly {
        extendsFrom annotationProcessor
    }
}

repositories {
    maven { url 'https://repo.spring.io/snapshot' }
    mavenCentral()
}

dependencies {
    implementation project(':shared')
    implementation project(':rdbms')
    implementation project(':ai')
    testImplementation 'org.springframework.boot:spring-boot-starter-test'
}

test {
    useJUnitPlatform()
}

jar {
    enabled = false
}

bootJar {
    launchScript()
    enabled = true
    manifest {
        attributes 'Main-Class': 'org.springframework.boot.loader.PropertiesLauncher'
    }
}

processResources {
    // exclude resources when build prod
    if (isProd) {
        exclude("application-dev.yml", "generatorConfig.xml")
    }
    // will replace the ${activeProfile} to activeProfile value in application.yml
    filesMatching('application.yml') {
        expand(project.properties)
    }
}

plugins {
    id 'java'
}

group 'cn.surveyking'
version 'v0.2.0'

repositories {
    mavenCentral()
}

dependencies {
    testImplementation 'org.junit.jupiter:junit-jupiter-api:5.7.0'
    testRuntimeOnly 'org.junit.jupiter:junit-jupiter-engine:5.7.0'

    implementation 'com.baomidou:mybatis-plus-boot-starter:3.5.0'

    implementation('org.flowable:flowable-spring-boot-starter:6.7.0'){
        exclude group: 'org.flowable', module: 'flowable-cmmn-spring-configurator'
        exclude group: 'org.flowable', module: 'flowable-spring-boot-starter-cmmn'
        exclude group: 'org.flowable', module: 'flowable-spring-boot-starter-dmn'
        exclude group: 'org.flowable', module: 'flowable-dmn-spring-configurator'
        exclude group: 'org.flowable', module: 'flowable-form-spring-configurator'
        exclude group: 'org.flowable', module: 'flowable-idm-spring-configurator'
    }
    implementation 'mysql:mysql-connector-java:8.0.26'
//    implementation 'com.h2database:h2:1.4.200'
    implementation project(':shared')
    implementation project(':rdbms')
}

test {
    useJUnitPlatform()
}
